const fetchOrders =
async () => {

  const {
    data,
    error
  } = await supabase
    .from("Orders")
    .select("*")
    .order("id", {
      ascending: false
    });

  if (error) {

    console.log(error);

    return;
  }

  setOrders(data || []);
};
const updateOrderStatus =
async (id, status) => {

  const { error } =
    await supabase
      .from("Orders")
      .update({
        status: status
      })
      .eq("id", id);

  if (error) {

    console.log(error);

    return;
  }

  // DELETE WHEN DELIVERED
  if (
    status ===
    "Delivered"
  ) {

    await supabase
      .from("Orders")
      .delete()
      .eq("id", id);
  }

  fetchOrders();
};

  useEffect(() => {

  fetchOrders();
  const liveOrders =
setInterval(() => {

  fetchOrders();

}, 3000);

  const checkSchedule =
    setInterval(async () => {

      const { data } =
        await supabase
          .from("Orders")
          .select("*");

      const savedOrders =
        data || [];

      const now = new Date();

      for (const order of savedOrders) {

        if (
          order.schedule_time &&
          !order.processed
        ) {

          const orderTime =
            new Date(
              order.schedule_time
            );

          if (now >= orderTime) {

            await supabase
              .from("Orders")
              .update({
                status: "Preparing",
                processed: true
              })
              .eq("id", order.id);
          }
        }
      }

      fetchOrders();

    }, 60000);

 return () => {

  clearInterval(checkSchedule);

  clearInterval(liveOrders);

};
}, []);
    const decreaseQtyMenu = (item) => {

  const existingItem = cart.find(
    (cartItem) => cartItem.name === item.name
  );

  if (!existingItem) return;

  if (existingItem.quantity === 1) {

    setCart(
      cart.filter(
        (cartItem) =>
          cartItem.name !== item.name
      )
    );

  } else {

    setCart(
      cart.map((cartItem) =>
        cartItem.name === item.name
          ? {
              ...cartItem,
              quantity:
                cartItem.quantity - 1
            }
          : cartItem
      )
    );

  }
};
