 const addToCart = (item) => {
  setShowFloatingCart(true);

  const existingItem = cart.find(
    (cartItem) => cartItem.name === item.name
  );

  if (existingItem) {

    setCart(
      cart.map((cartItem) =>
        cartItem.name === item.name
          ? {
              ...cartItem,
              quantity:
                cartItem.quantity + 1
            }
          : cartItem
      )
    );

  } else {

    setCart([
      ...cart,
      {
        ...item,
        quantity: 1
      }
    ]);

  }
};
  const placeOrder = async () => {

  playSound("/sounds/cart.mp3");

  if (cart.length === 0) {

    alert("🛒 Cart Empty");

    return;
  }

  const total =
    cart.reduce(

      (sum, item) =>

        sum +
        item.price *
          item.quantity,

      0
    );

  const now =
    new Date();

  const scheduled =
    scheduleTime ||
    "Instant Order";

  const orderId =
    "ORD" +
    Math.floor(
      100000 +
      Math.random() * 900000
    );

  const newOrder = {

    order_no: orderId,

    customer: userName,

    phone: phoneNumber,

    payment: paymentMethod,

    total: total,

    items: cart,

    status: scheduled ===
      "Instant Order"
        ? "Preparing"
        : "Scheduled",

    processed: false,

    order_date:
      now.toLocaleDateString(),

    order_time:
      now.toLocaleTimeString(),

    schedule_time:
      scheduled
  };

  const { error } =
    await supabase
      .from("Orders")
      .insert([newOrder]);

  if (error) {

    console.log(error);

    alert(
      JSON.stringify(error)
    );

    return;
  }

  setOrderNumber(orderId);

  setCart([]);

  setScheduleTime("");

  setScreen("success");

  fetchOrders();
};

  

